{
  "handoff_brief": {
    "recipient": "Shaq",
    "task_context": "Implement a loyalty points module in TypeScript. Two pure functions in a single loyalty.ts file, no external dependencies. Bird defined the domain rules and MJ designed the architecture. This is a self-contained module with no database or API layer — just business logic.",
    "domain_rules": [
      {
        "rule": "A customer earns 1 point per dollar spent, rounded down to the nearest integer (floor)",
        "testable_assertion": "earnPoints(customerId, 47.80) returns 47; earnPoints(customerId, 0.99) returns 0"
      },
      {
        "rule": "All points expire after 12 months of account inactivity, defined as no purchase in 12 calendar months",
        "testable_assertion": "checkExpiry(customerId) marks all points expired when last_purchase_date is more than 12 calendar months ago"
      }
    ],
    "architecture_guidance": [
      {
        "decision": "Pure TypeScript module in loyalty.ts with no external dependencies",
        "implementation_note": "Export two functions: earnPoints(customerId: string, purchaseAmount: number) and checkExpiry(customerId: string). No database calls — these are pure business logic functions that receive data and return results."
      },
      {
        "decision": "Use Math.floor for point rounding",
        "implementation_note": "Math.floor(purchaseAmount) — not Math.round, not Math.trunc. Floor specifically handles negative edge cases differently, but for positive purchase amounts the distinction is academic. Still, use Math.floor as specified."
      },
      {
        "decision": "checkExpiry needs a way to receive the last purchase date",
        "implementation_note": "MJ spec says compare last_purchase_date against current date. Since these are pure functions with no DB access, checkExpiry will need last_purchase_date as a parameter or the function signature needs adjustment. Recommend: checkExpiry(customerId: string, lastPurchaseDate: Date, currentDate?: Date) — the optional currentDate param enables deterministic testing."
      }
    ],
    "acceptance_criteria": [
      {
        "criterion": "AC1: Standard purchase earns floor-rounded points",
        "given": "A purchase of $47.80",
        "when": "earnPoints is called",
        "then": "47 points are earned"
      },
      {
        "criterion": "AC2: Sub-dollar purchase earns zero points",
        "given": "A purchase of $0.99",
        "when": "earnPoints is called",
        "then": "0 points are earned"
      },
      {
        "criterion": "AC3: Inactive account has points expired",
        "given": "An account with no purchase in the last 12 months",
        "when": "checkExpiry is called",
        "then": "All points are marked expired"
      }
    ],
    "terminology_alignment": [
      {
        "domain_term": "account inactivity",
        "technical_term": "last_purchase_date comparison",
        "definition": "An account is inactive when no purchase has been made in 12 calendar months. Technically: last_purchase_date is before the date 12 calendar months prior to today."
      },
      {
        "domain_term": "points are marked expired",
        "technical_term": "return value from checkExpiry",
        "definition": "checkExpiry should return a result indicating whether all points are expired (e.g., { expired: boolean }). 'Marked expired' means the function signals expiry — it does not mutate state since these are pure functions."
      }
    ],
    "contradictions_resolved": [
      {
        "conflict": "Bird specifies '12 months of inactivity' but MJ specifies 'current date minus 365 days'. These are not equivalent — 12 calendar months can be 365, 366, or vary by start month.",
        "resolution": "Bird is domain authority. Use 12 calendar months (e.g., if today is 2026-03-20, expiry threshold is 2025-03-20). Implement by subtracting 12 months from current date using Date APIs, not by subtracting 365 days. This preserves Bird's intent and handles leap years correctly."
      }
    ],
    "open_questions": [
      "Should earnPoints reject negative or zero purchaseAmount, or just return 0? Bird's rules don't cover negative amounts. Recommend: guard clause returning 0 for purchaseAmount <= 0.",
      "What does checkExpiry return? Bird says 'marked expired' but the module is stateless. Shaq should return a typed result like { expired: boolean; pointsExpired: number } or similar — clarify with Bird if richer return shape is needed.",
      "Does checkExpiry need to know about point balances, or just return the expired/not-expired boolean? Current spec implies it only checks the date condition."
    ]
  },
  "escalations": [],
  "confidence": {
    "level": 82,
    "high_confidence_areas": [
      "earnPoints logic — Bird's rules and MJ's architecture are fully aligned on floor rounding",
      "Module structure — pure TypeScript, no dependencies, two exported functions"
    ],
    "low_confidence_areas": [
      "checkExpiry function signature — MJ's spec assumes DB access for last_purchase_date but also says pure functions with no external dependencies. Shaq will need to add lastPurchaseDate as a parameter.",
      "Return types — neither Bird nor MJ specified return shapes explicitly"
    ],
    "assumptions": [
      "checkExpiry should accept lastPurchaseDate as a parameter since the module is stateless",
      "12 calendar months is the correct interpretation of Bird's '12 months' rule, overriding MJ's 365-day implementation",
      "An injectable currentDate parameter is appropriate for testability"
    ]
  }
}

